// Behavioral coverage of TsSqlProcessingError reasons the builders surface:
//   - NO_AUTOGENERATED_ID_COLUMN_FOUND — both arms: a table with NO
//     autogenerated PK, and a table with TWO,
//   - COLUMN_FOR_INSERT_COMING_FROM_SUBQUERY_NOT_IN_TABLE — an insert-from-
//     select projecting a key that is not a column of the target table.
// These reasons are thrown by the dialect-agnostic builders, so the throw is
// identical on every dialect (no per-cell SQL).

import { afterAll, beforeAll, beforeEach, describe, expect, test } from '../../../../lib/testRunner.js'
import { TsSqlError } from '../../../../../src/TsSqlError.js'
import { Table } from '../../../../../src/Table.js'
import { tCountry, tProject, type DBConnection } from '../../domain/connection.js'
import { ctx } from './setup.js'

function reasonOf(e: unknown): string | undefined {
    if (e instanceof TsSqlError) return e.errorReason.reason
    return undefined
}

// A `project_member` link table a developer MISCONFIGURED by declaring BOTH
// `id` and `memberId` as autogeneratedPrimaryKey — never executed against a
// real DB (the guard throws before any SQL is built), so no schema/seed is
// needed. Reaches the "must define only one autogenerated primary key" arm.
const tMisconfiguredMembership = new class TMisconfiguredMembership extends Table<DBConnection, 'TMisconfiguredMembership'> {
    id       = this.autogeneratedPrimaryKey('id', 'int')
    memberId = this.autogeneratedPrimaryKey('member_id', 'int')
    role     = this.column('role', 'string')
    constructor() { super('project_member') }
}()

// A `virtualColumnFromFragment` whose builder callback returns a NON-value-source
// (reachable only via a cast — the typer requires the callback to return a value
// source). The stub carries no-op private hooks so the column survives the
// table/column registration walk and reaches `__toSql`, where `hasToSql` rejects
// it (no `__toSql` method) and the INVALID_SQL_FRAGMENT_RETURN_TYPE guard fires.
// No schema/seed is needed: the throw precedes any execution.
const notAValueSource = {
    __addWiths() {},
    __registerTableOrView() {},
    __registerRequiredColumn() {},
    __getOldValues() { return undefined },
    __getValuesForInsert() { return undefined },
    __isAllowed() { return true },
    __hasAggregation() { return false },
}
const tBadVirtualColumn = new class TBadVirtualColumn extends Table<DBConnection, 'TBadVirtualColumn'> {
    id  = this.autogeneratedPrimaryKey('id', 'int')
    // tests-audit-disable-next-line as-any -- feeds a non-value-source to the INVALID_SQL_FRAGMENT_RETURN_TYPE runtime guard asserted below (the typer requires a value source)
    bad = this.virtualColumnFromFragment('string', (() => notAValueSource) as any)
    constructor() { super('issue') }
}()

describe(ctx.label, () => {
    beforeAll(() => ctx.up(), ctx.timeoutMs)
    afterAll(() => ctx.down(), ctx.timeoutMs)
    beforeEach(() => { ctx.reset() })

    test('returningLastInsertedId on a provided-PK table throws NO_AUTOGENERATED_ID_COLUMN_FOUND', () => {
        // tCountry's PK is the provided string `code` — no autogenerated id, so
        // `returningLastInsertedId()` has no id column to return. The cast
        // bypasses the compile-time guard (the method is typed off for
        // provided-PK tables) to reach the runtime guard.
        let caught: unknown
        try {
            (ctx.conn.insertInto(tCountry).values({ code: 'XX', name: 'X', region: 'X' }) as any)
                .returningLastInsertedId()
        } catch (e) {
            caught = e
        }
        expect(reasonOf(caught)).toBe('NO_AUTOGENERATED_ID_COLUMN_FOUND')
    })

    test('returningLastInsertedId on a two-autogenerated-PK table throws NO_AUTOGENERATED_ID_COLUMN_FOUND', () => {
        // `returningLastInsertedId()` requires EXACTLY ONE autogenerated
        // primary key; a table with two reaches the "must have defined only
        // one" branch.
        let caught: unknown
        try {
            (ctx.conn.insertInto(tMisconfiguredMembership).values({ role: 'X' }) as any)
                .returningLastInsertedId()
        } catch (e) {
            caught = e
        }
        expect(reasonOf(caught)).toBe('NO_AUTOGENERATED_ID_COLUMN_FOUND')
    })

    test('insert-from-select with an unknown projected key throws COLUMN_FOR_INSERT_COMING_FROM_SUBQUERY_NOT_IN_TABLE', async () => {
        // The insert-from-select column list is taken from the select's
        // projection keys; a key that is not a column of the target table
        // (`notACountryColumn`) reaches the guard during SQL building. The cast
        // bypasses the compile-time projection-shape check.
        ctx.mockNext(1)
        let caught: unknown
        try {
            const badSelect = ctx.conn.selectFrom(tProject)
                .select({
                    code:             tProject.slug,
                    name:             tProject.name,
                    region:           tProject.name,
                    notACountryColumn: tProject.id,
                }) as any
            await (ctx.conn.insertInto(tCountry) as any).from(badSelect).executeInsert()
        } catch (e) {
            caught = e
        }
        expect(reasonOf(caught)).toBe('COLUMN_FOR_INSERT_COMING_FROM_SUBQUERY_NOT_IN_TABLE')
    })
    test('shaped update mapping a column not in the table throws MAPPED_SHAPED_COLUMN_NOT_IN_TABLE', async () => {
        // `shapedAs({ projectName: 'nonexistent' })` maps a shape property to a
        // column that does not exist on the target table; the guard fires when the
        // SET clause is built. The cast bypasses the compile-time shape validation
        // (UpdateShape only accepts real column names) to reach the runtime guard.
        let caught: unknown
        try {
            await (ctx.conn.update(tProject) as any)
                .shapedAs({ projectName: 'nonexistent' })
                .set({ projectName: 'X' })
                .where(tProject.id.equals(1))
                .executeUpdate()
        } catch (e) {
            caught = e
        }
        expect(reasonOf(caught)).toBe('MAPPED_SHAPED_COLUMN_NOT_IN_TABLE')
    })

    test('selecting a virtual column whose builder returns a non-value-source throws INVALID_SQL_FRAGMENT_RETURN_TYPE', async () => {
        // `tBadVirtualColumn.bad` is a virtualColumnFromFragment whose builder
        // callback returns a non-value-source object (no __toSql). The guard fires
        // when the column is rendered to SQL (`__toSql`), so the SELECT never
        // reaches the driver — the throw is identical on every dialect.
        let caught: unknown
        try {
            await ctx.conn.selectFrom(tBadVirtualColumn)
                .select({ bad: tBadVirtualColumn.bad })
                .executeSelectMany()
        } catch (e) {
            caught = e
        }
        expect(reasonOf(caught)).toBe('INVALID_SQL_FRAGMENT_RETURN_TYPE')
    })

    test('update-returning-old-values-on-a-table-without-a-primary-key-throws-no-primary-key-found', async () => {
        // An old-values update captures the pre-update row by joining it back to
        // the updated row on the primary key; a table with NO primary key has no
        // column to key that join on, so the build throws. oldValues() is typed
        // `never` on a table with no autogenerated primary key, so the cast
        // reaches the runtime guard. The stub never executes against a real DB —
        // the throw precedes any execution, so no schema/seed is needed.
        const tEventLog = new class TEventLog extends Table<DBConnection, 'TEventLog'> {
            eventType = this.column('event_type', 'string')
            payload   = this.column('payload', 'string')
            constructor() { super('event_log') }
        }()
        let caught: unknown
        try {
            const oldEventLog = (tEventLog as any).oldValues()
            await (ctx.conn.update(tEventLog) as any)
                .set({ eventType: 'updated' })
                .where(tEventLog.eventType.equals('created'))
                .returning({ old: oldEventLog.eventType, new: tEventLog.eventType })
                .executeUpdateOne()
        } catch (e) {
            caught = e
        }
        expect(reasonOf(caught)).toBe('NO_PRIMARY_KEY_FOUND')
    })

})
